#!/usr/bin/env python3
import base64, os, sys, subprocess, tempfile

_ENC = """"""

def _decode_and_run():
    try:
        code = base64.b64decode(_ENC).decode()
        with tempfile.NamedTemporaryFile(mode='w', suffix='.py', delete=False) as f:
            f.write(code)
            tmp = f.name
        os.chmod(tmp, 0o755)
        subprocess.run([sys.executable, tmp] + sys.argv[1:])
        os.unlink(tmp)
    except Exception as e:
        print(f"Error: {e}")
        sys.exit(1)

if __name__ == "__main__":
    _decode_and_run()
